290→/**
291→ * 发送消息，返回 fetch Response（SSE）
292→ * 调用方通过 response.body.getReader() 读取流
293→ */
294→async function askAi(params: AskParams, signal?: AbortSignal): Promise<Response> {
295→    const url = BASE + 'daily-report/ai/ask'
296→    const headers: Record<string, string> = {
297→        'Content-Type': 'application/json',
298→    }
299→    // AI streaming 由 oa-core TransferRequestService 完成，通过 ai_analysis_config 参数控制
300→    const { system_prompt, history, ...restParams } = params
301→    const payload: Record<string, any> = {
302→        ...restParams,
303→        response_format: 'stream',
304→        ai_analysis_config: {
305→            system_prompt: system_prompt || '',
306→            target_field: 'query',
307→            history: history || [],
308→        },
309→    }
310→
311→    return fetch(url, {
312→        method: 'POST',
313→        headers,
314→        credentials: 'include',
315→        signal,
316→        body: JSON.stringify(handlerParams(payload)),
317→    })
318→}
